import React from "react"
import Header from "../components/Header"
import { Link, useNavigate } from 'react-router-dom'


class SignUp extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            name: "",
            password: ""
        }
    }
    render() {
        return (
            <div>
                <Header />
            <form className="auth-form">
                <input placeholder="Логин" onChange={(e) => this.setState({name: e.target.value})} />
                <input placeholder="Пароль" onChange={(e) => this.setState({password: e.target.value})} />
                <Link to="../home">
                    <button onClick={() => this.props.onAdd({name: this.state.name, password: this.state.password})}>Войти</button>
                </Link>
                <h3>Или</h3>
            </form>
            </div>
        )
    }
}

export default SignUp
